use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use uuid::Uuid;

use crate::agent_id::AgentId;

/// A specific permission that can be granted to an agent.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(tag = "type", rename_all = "snake_case")]
pub enum Capability {
    FileRead {
        path_glob: String,
    },
    FileWrite {
        path_glob: String,
    },
    WebSearch,
    NetworkAccess {
        hosts: Vec<String>,
    },
    SpawnChild {
        allowed_agents: Vec<String>,
    },
    ToolInvoke {
        tool_name: String,
    },
    MessageSend {
        target_agents: Vec<String>,
    },
    Custom {
        name: String,
        params: serde_json::Value,
    },
}

/// Rate limiting configuration for a capability.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct RateLimit {
    pub max_per_minute: u32,
}

/// Constraints that narrow a capability's scope.
#[derive(Debug, Clone, Default, PartialEq, Eq, Serialize, Deserialize)]
pub struct Constraints {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub max_invocations: Option<u64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub rate_limit: Option<RateLimit>,
}

/// An unforgeable token granting a specific capability to a specific agent.
///
/// Tokens are created by the kernel at agent spawn time based on the
/// agent's manifest. They can only be narrowed (adding more constraints),
/// never escalated.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CapabilityToken {
    pub id: Uuid,
    pub agent_id: AgentId,
    pub capability: Capability,
    pub constraints: Constraints,
    pub issued_at: DateTime<Utc>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub expires_at: Option<DateTime<Utc>>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub revoked_at: Option<DateTime<Utc>>,
    /// Number of times this token has been used. Compared against max_invocations.
    #[serde(default)]
    pub invocation_count: u64,
}

impl CapabilityToken {
    /// Issue a new capability token for an agent.
    pub fn issue(agent_id: AgentId, capability: Capability, constraints: Constraints) -> Self {
        Self {
            id: Uuid::new_v4(),
            agent_id,
            capability,
            constraints,
            issued_at: Utc::now(),
            expires_at: None,
            revoked_at: None,
            invocation_count: 0,
        }
    }

    /// Check if this token has expired.
    pub fn is_expired(&self) -> bool {
        self.expires_at.is_some_and(|exp| Utc::now() > exp)
    }

    /// Check if this token has been revoked.
    pub fn is_revoked(&self) -> bool {
        self.revoked_at.is_some()
    }

    /// Revoke this token. Once revoked, `permits()` always returns false.
    pub fn revoke(&mut self) {
        self.revoked_at = Some(Utc::now());
    }

    /// Check if this token grants the requested capability.
    /// Checks expiry, revocation, and max_invocations constraint.
    pub fn permits(&self, requested: &Capability) -> bool {
        if self.is_expired() || self.is_revoked() {
            return false;
        }
        // Check max_invocations constraint
        if let Some(max) = self.constraints.max_invocations {
            if self.invocation_count >= max {
                return false;
            }
        }
        self.capability_matches(requested)
    }

    /// Record a use of this token. Call after a successful operation.
    /// Returns false if the token has exhausted its invocations.
    pub fn record_use(&mut self) -> bool {
        self.invocation_count += 1;
        if let Some(max) = self.constraints.max_invocations {
            self.invocation_count <= max
        } else {
            true
        }
    }

    /// Check if this token has exhausted its invocation limit.
    pub fn is_exhausted(&self) -> bool {
        self.constraints
            .max_invocations
            .is_some_and(|max| self.invocation_count >= max)
    }

    fn capability_matches(&self, requested: &Capability) -> bool {
        match (&self.capability, requested) {
            (
                Capability::FileRead { path_glob: granted },
                Capability::FileRead { path_glob: req },
            ) => glob_matches(granted, req),
            (
                Capability::FileWrite { path_glob: granted },
                Capability::FileWrite { path_glob: req },
            ) => glob_matches(granted, req),
            (Capability::WebSearch, Capability::WebSearch) => true,
            (
                Capability::NetworkAccess { hosts: granted },
                Capability::NetworkAccess { hosts: req },
            ) => req.iter().all(|h| granted.contains(h)),
            (
                Capability::SpawnChild {
                    allowed_agents: granted,
                },
                Capability::SpawnChild {
                    allowed_agents: req,
                },
            ) => req.iter().all(|a| granted.contains(a)),
            (
                Capability::ToolInvoke { tool_name: granted },
                Capability::ToolInvoke { tool_name: req },
            ) => granted == req || granted == "*",
            (
                Capability::MessageSend {
                    target_agents: granted,
                },
                Capability::MessageSend { target_agents: req },
            ) => req
                .iter()
                .all(|a| granted.iter().any(|g| g == "*" || g == a)),
            (Capability::Custom { name: gn, .. }, Capability::Custom { name: rn, .. }) => gn == rn,
            _ => false,
        }
    }

    /// Create a narrowed copy of this token with additional constraints.
    pub fn narrow(&self, additional: Constraints) -> Self {
        let mut narrowed = self.clone();
        narrowed.id = Uuid::new_v4();
        if let Some(max) = additional.max_invocations {
            narrowed.constraints.max_invocations = Some(
                narrowed
                    .constraints
                    .max_invocations
                    .map_or(max, |existing| existing.min(max)),
            );
        }
        if let Some(rate) = additional.rate_limit {
            narrowed.constraints.rate_limit = Some(narrowed.constraints.rate_limit.map_or(
                rate.clone(),
                |existing| RateLimit {
                    max_per_minute: existing.max_per_minute.min(rate.max_per_minute),
                },
            ));
        }
        narrowed
    }
}

/// Glob matching with path normalization to prevent traversal attacks.
///
/// Normalizes paths by resolving `..` and `.` components lexically (without
/// touching the filesystem) before matching. This prevents attacks like
/// `/data/../etc/passwd` matching a `/data/*` grant.
fn glob_matches(pattern: &str, path: &str) -> bool {
    if pattern == "*" {
        return true;
    }
    let normalized = normalize_path(path);
    if let Some(prefix) = pattern.strip_suffix('*') {
        let norm_prefix = normalize_path(prefix);
        normalized.starts_with(&norm_prefix)
    } else {
        let norm_pattern = normalize_path(pattern);
        norm_pattern == normalized
    }
}

/// Lexical path normalization: resolves `.` and `..` without filesystem access.
/// Prevents path traversal attacks while working inside containers where
/// paths may not exist yet (e.g., `/output/` before any file is written).
fn normalize_path(path: &str) -> String {
    let mut parts: Vec<&str> = Vec::new();
    for component in path.split('/') {
        match component {
            "" | "." => {}
            ".." => { parts.pop(); }
            other => parts.push(other),
        }
    }
    if path.starts_with('/') {
        format!("/{}", parts.join("/"))
    } else {
        parts.join("/")
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn test_agent() -> AgentId {
        AgentId::new()
    }

    #[test]
    fn file_read_glob_matching() {
        let token = CapabilityToken::issue(
            test_agent(),
            Capability::FileRead {
                path_glob: "/data/project/*".into(),
            },
            Constraints::default(),
        );
        assert!(token.permits(&Capability::FileRead {
            path_glob: "/data/project/foo.txt".into()
        }));
        assert!(!token.permits(&Capability::FileRead {
            path_glob: "/etc/passwd".into()
        }));
    }

    #[test]
    fn tool_invoke_wildcard() {
        let token = CapabilityToken::issue(
            test_agent(),
            Capability::ToolInvoke {
                tool_name: "*".into(),
            },
            Constraints::default(),
        );
        assert!(token.permits(&Capability::ToolInvoke {
            tool_name: "web_search".into()
        }));
    }

    #[test]
    fn capability_type_mismatch() {
        let token =
            CapabilityToken::issue(test_agent(), Capability::WebSearch, Constraints::default());
        assert!(!token.permits(&Capability::FileRead {
            path_glob: "/tmp/*".into()
        }));
    }

    #[test]
    fn narrowing_reduces_constraints() {
        let token = CapabilityToken::issue(
            test_agent(),
            Capability::WebSearch,
            Constraints {
                max_invocations: Some(100),
                rate_limit: None,
            },
        );
        let narrowed = token.narrow(Constraints {
            max_invocations: Some(10),
            rate_limit: None,
        });
        assert_eq!(narrowed.constraints.max_invocations, Some(10));
    }

    #[test]
    fn path_traversal_blocked() {
        let token = CapabilityToken::issue(
            test_agent(),
            Capability::FileRead { path_glob: "/data/*".into() },
            Constraints::default(),
        );
        // Direct traversal
        assert!(!token.permits(&Capability::FileRead {
            path_glob: "/data/../etc/passwd".into()
        }));
        // Double traversal
        assert!(!token.permits(&Capability::FileRead {
            path_glob: "/data/foo/../../etc/shadow".into()
        }));
        // Dot components
        assert!(!token.permits(&Capability::FileRead {
            path_glob: "/data/./../../etc/passwd".into()
        }));
        // Legitimate subpath still works
        assert!(token.permits(&Capability::FileRead {
            path_glob: "/data/project/file.txt".into()
        }));
    }

    #[test]
    fn normalize_path_works() {
        assert_eq!(normalize_path("/data/../etc/passwd"), "/etc/passwd");
        assert_eq!(normalize_path("/data/foo/../../etc"), "/etc");
        assert_eq!(normalize_path("/data/./file.txt"), "/data/file.txt");
        assert_eq!(normalize_path("/data/project/"), "/data/project");
        assert_eq!(normalize_path("/"), "/");
    }

    #[test]
    fn max_invocations_enforced() {
        let mut token = CapabilityToken::issue(
            test_agent(),
            Capability::WebSearch,
            Constraints {
                max_invocations: Some(3),
                rate_limit: None,
            },
        );
        // First 3 uses: permitted
        assert!(token.permits(&Capability::WebSearch));
        token.record_use();
        assert!(token.permits(&Capability::WebSearch));
        token.record_use();
        assert!(token.permits(&Capability::WebSearch));
        token.record_use();
        // 4th use: denied
        assert!(!token.permits(&Capability::WebSearch));
        assert!(token.is_exhausted());
    }

    #[test]
    fn no_max_invocations_unlimited() {
        let mut token = CapabilityToken::issue(
            test_agent(),
            Capability::WebSearch,
            Constraints::default(), // no max_invocations
        );
        for _ in 0..1000 {
            assert!(token.permits(&Capability::WebSearch));
            token.record_use();
        }
        assert!(!token.is_exhausted());
    }

    #[test]
    fn revoked_token_denies_access() {
        let mut token = CapabilityToken::issue(
            test_agent(),
            Capability::FileRead { path_glob: "/data/*".into() },
            Constraints::default(),
        );
        // Before revocation: permits
        assert!(token.permits(&Capability::FileRead { path_glob: "/data/file.txt".into() }));
        assert!(!token.is_revoked());

        // Revoke
        token.revoke();

        // After revocation: denies
        assert!(token.is_revoked());
        assert!(token.revoked_at.is_some());
        assert!(!token.permits(&Capability::FileRead { path_glob: "/data/file.txt".into() }));
    }

    #[test]
    fn revoked_token_roundtrips_json() {
        let mut token = CapabilityToken::issue(
            test_agent(),
            Capability::WebSearch,
            Constraints::default(),
        );
        token.revoke();
        let json = serde_json::to_string(&token).unwrap();
        let parsed: CapabilityToken = serde_json::from_str(&json).unwrap();
        assert!(parsed.is_revoked());
        assert!(!parsed.permits(&Capability::WebSearch));
    }

    #[test]
    fn token_roundtrips_json() {
        let token = CapabilityToken::issue(
            test_agent(),
            Capability::NetworkAccess {
                hosts: vec!["api.example.com".into()],
            },
            Constraints::default(),
        );
        let json = serde_json::to_string(&token).unwrap();
        let parsed: CapabilityToken = serde_json::from_str(&json).unwrap();
        assert_eq!(token.capability, parsed.capability);
    }
}

use std::sync::Arc;

use aaos_core::{AgentId, TokenBudget};
use aaos_llm::{ContentBlock, LlmClient, Message};
use aaos_llm::types::{CompletionRequest, CompletionResponse};

// ---------------------------------------------------------------------------
// Free helper functions (live here, NOT in aaos-core, because they need Message)
// ---------------------------------------------------------------------------

/// Count characters in a single message, handling all variants.
pub fn message_chars(msg: &Message) -> usize {
    match msg {
        Message::User { content } => content.len(),
        Message::Assistant { content } => content
            .iter()
            .map(|block| match block {
                ContentBlock::Text { text } => text.len(),
                ContentBlock::ToolUse { name, input, .. } => name.len() + input.to_string().len(),
            })
            .sum(),
        Message::ToolResult {
            tool_use_id,
            content,
            ..
        } => tool_use_id.len() + content.to_string().len(),
        Message::Summary { content, .. } => content.len(),
    }
}

/// Estimate token count for a slice of messages using chars/4 heuristic.
pub fn estimate_tokens(messages: &[Message]) -> u32 {
    let total_chars: usize = messages.iter().map(|m| message_chars(m)).sum();
    (total_chars / 4) as u32
}

/// Return true if the estimated token count exceeds `threshold` fraction of the budget.
pub fn should_summarize(budget: &TokenBudget, messages: &[Message], threshold: f32) -> bool {
    let estimated = estimate_tokens(messages);
    estimated as f32 > budget.max_tokens as f32 * threshold
}

// ---------------------------------------------------------------------------
// PreparedContext / SummarizationResult
// ---------------------------------------------------------------------------

/// Result of context preparation, returned to the caller.
pub struct PreparedContext {
    /// Messages to send to the LLM (Summary variants removed).
    pub messages: Vec<Message>,
    /// System prompt, potentially prefixed with summary text.
    pub system_prompt: String,
    /// If summarization occurred, this contains the result.
    pub summarization: Option<SummarizationResult>,
}

/// Details of a summarization that occurred during context preparation.
pub struct SummarizationResult {
    /// The raw messages that were archived (removed from active history).
    pub archived_messages: Vec<Message>,
    /// The Summary message to store in the session (for future re-summarization).
    pub summary: Message,
    /// Message indices from original history that were summarized.
    pub source_range: (usize, usize),
    /// Estimated tokens freed by this summarization.
    pub tokens_saved_estimate: u32,
}

// ---------------------------------------------------------------------------
// ContextManager
// ---------------------------------------------------------------------------

/// Manages agent context windows by summarizing and archiving old messages.
pub struct ContextManager {
    llm_client: Arc<dyn LlmClient>,
    budget: TokenBudget,
    summarization_model: String,
    summarization_threshold: f32,
}

impl ContextManager {
    pub fn new(
        llm_client: Arc<dyn LlmClient>,
        budget: TokenBudget,
        model: String,
        threshold: f32,
    ) -> Self {
        Self {
            llm_client,
            budget,
            summarization_model: model,
            summarization_threshold: threshold,
        }
    }

    /// Prepare context for the next LLM call.
    ///
    /// Does NOT mutate history. Returns `PreparedContext` with:
    /// - messages: the message list to send (Summary variants folded into system prompt)
    /// - system_prompt: potentially prefixed with summary text
    /// - summarization: if summarization occurred, the archived segment for the caller to persist
    ///
    /// The caller MUST, in order:
    /// 1. Archive the segment (if summarization is Some)
    /// 2. Replace archived messages with the Summary in the in-memory history
    pub async fn prepare_context(
        &self,
        history: &[Message],
        system_prompt: &str,
    ) -> Result<PreparedContext, String> {
        if !should_summarize(&self.budget, history, self.summarization_threshold) {
            // No summarization needed — just fold any existing Summary messages into the prompt
            return Ok(Self::fold_summaries_into_prompt(history, system_prompt));
        }

        // Select messages to summarize: oldest messages up to ~40% of the context
        let target_tokens = (self.budget.max_tokens as f32 * 0.4) as u32;
        let selection_end = Self::select_summarization_boundary(history, target_tokens);

        if selection_end == 0 {
            // Nothing to summarize (edge case: single huge message)
            return Ok(Self::fold_summaries_into_prompt(history, system_prompt));
        }

        let selected = &history[..selection_end];

        // Guard: make sure the selected messages fit in the summarization model's context
        let summarization_model_max =
            self.llm_client.max_context_tokens(&self.summarization_model);
        let selected_tokens = estimate_tokens(selected);
        let guarded_end = if selected_tokens > summarization_model_max * 9 / 10 {
            // Trim selection to fit
            Self::select_summarization_boundary(history, summarization_model_max * 7 / 10)
        } else {
            selection_end
        };

        if guarded_end == 0 {
            return Ok(Self::fold_summaries_into_prompt(history, system_prompt));
        }

        let to_summarize = &history[..guarded_end];

        // Format selected messages as text for the summarization prompt
        let formatted = Self::format_messages_for_summary(to_summarize);

        // Call the summarization LLM
        let summary_result = self.call_summarization_llm(&formatted).await;

        match summary_result {
            Ok(summary_text) => {
                let tokens_before = estimate_tokens(to_summarize);
                let tokens_after = (summary_text.len() / 4) as u32;
                let tokens_saved = tokens_before.saturating_sub(tokens_after);

                let summary_msg = Message::Summary {
                    content: summary_text.clone(),
                    messages_summarized: guarded_end as u32,
                    source_range: (0, guarded_end - 1),
                };

                let summarization = SummarizationResult {
                    archived_messages: to_summarize.to_vec(),
                    summary: summary_msg.clone(),
                    source_range: (0, guarded_end - 1),
                    tokens_saved_estimate: tokens_saved,
                };

                // Build the new message list: summary_msg + remaining history
                let mut new_history = vec![summary_msg];
                new_history.extend_from_slice(&history[guarded_end..]);

                let prepared = Self::fold_summaries_into_prompt(&new_history, system_prompt);

                Ok(PreparedContext {
                    messages: prepared.messages,
                    system_prompt: prepared.system_prompt,
                    summarization: Some(summarization),
                })
            }
            Err(e) => {
                // Fallback: no-op on failure (logs warning)
                tracing::warn!("Summarization failed ({e}), falling back to no-op");
                Ok(Self::fold_summaries_into_prompt(history, system_prompt))
            }
        }
    }

    /// Fold any Summary messages at the start of history into the system prompt prefix.
    /// Returns PreparedContext with summaries removed from messages and prepended to system_prompt.
    fn fold_summaries_into_prompt(history: &[Message], system_prompt: &str) -> PreparedContext {
        let mut summary_texts = Vec::new();
        let mut first_non_summary = 0;

        for (i, msg) in history.iter().enumerate() {
            match msg {
                Message::Summary { content, .. } => {
                    summary_texts.push(content.clone());
                    first_non_summary = i + 1;
                }
                _ => break,
            }
        }

        let final_system = if summary_texts.is_empty() {
            system_prompt.to_string()
        } else {
            let prefix = summary_texts.join("\n\n");
            format!("[Previous conversation summary]\n{prefix}\n\n{system_prompt}")
        };

        let messages = history[first_non_summary..].to_vec();

        PreparedContext {
            messages,
            system_prompt: final_system,
            summarization: None,
        }
    }

    /// Select how many messages from the start to summarize.
    /// Respects atomic tool call/result pairs.
    /// Returns the exclusive end index.
    fn select_summarization_boundary(history: &[Message], target_tokens: u32) -> usize {
        let mut accumulated_tokens: u32 = 0;
        let mut boundary = 0;

        for (i, msg) in history.iter().enumerate() {
            let msg_tokens = (message_chars(msg) / 4) as u32;
            accumulated_tokens += msg_tokens;

            if accumulated_tokens >= target_tokens {
                boundary = Self::adjust_boundary_for_tool_pairs(history, i + 1);
                break;
            }
        }

        // If we went through all messages without hitting target, summarize half
        if boundary == 0 && !history.is_empty() {
            boundary = Self::adjust_boundary_for_tool_pairs(history, history.len() / 2);
        }

        boundary
    }

    /// Adjust boundary to avoid splitting Assistant(ToolUse) / ToolResult pairs.
    /// If the message at boundary-1 is an Assistant with ToolUse, include all subsequent ToolResults.
    /// If the message at boundary is a ToolResult, back up to before its Assistant message.
    fn adjust_boundary_for_tool_pairs(history: &[Message], mut boundary: usize) -> usize {
        if boundary == 0 || boundary > history.len() {
            return boundary;
        }

        // Check if the last included message is an Assistant with tool_use
        if let Message::Assistant { content } = &history[boundary - 1] {
            let has_tool_use = content
                .iter()
                .any(|b| matches!(b, ContentBlock::ToolUse { .. }));
            if has_tool_use {
                // Include all following ToolResult messages
                while boundary < history.len() {
                    if matches!(&history[boundary], Message::ToolResult { .. }) {
                        boundary += 1;
                    } else {
                        break;
                    }
                }
            }
        }

        // Check if the boundary starts on a ToolResult — back up
        if boundary < history.len() {
            if matches!(&history[boundary], Message::ToolResult { .. }) {
                // Find the Assistant message before this ToolResult
                while boundary > 0 {
                    boundary -= 1;
                    if matches!(&history[boundary], Message::Assistant { .. }) {
                        break;
                    }
                }
            }
        }

        boundary
    }

    /// Format messages as readable text for the summarization LLM.
    fn format_messages_for_summary(messages: &[Message]) -> String {
        let mut lines = Vec::new();
        for msg in messages {
            match msg {
                Message::User { content } => {
                    lines.push(format!("User: {content}"));
                }
                Message::Assistant { content } => {
                    for block in content {
                        match block {
                            ContentBlock::Text { text } => {
                                lines.push(format!("Assistant: {text}"));
                            }
                            ContentBlock::ToolUse { name, input, .. } => {
                                lines.push(format!("Assistant [tool_use: {name}]: {input}"));
                            }
                        }
                    }
                }
                Message::ToolResult {
                    tool_use_id,
                    content,
                    is_error,
                } => {
                    let label = if *is_error { "error" } else { "result" };
                    lines.push(format!("Tool {label} ({tool_use_id}): {content}"));
                }
                Message::Summary { content, .. } => {
                    lines.push(format!("Previous summary: {content}"));
                }
            }
        }
        lines.join("\n")
    }

    /// Call the LLM to produce a summary of the formatted conversation.
    async fn call_summarization_llm(&self, formatted_text: &str) -> Result<String, String> {
        let request = CompletionRequest {
            agent_id: AgentId::new(), // ephemeral ID for summarization
            model: self.summarization_model.clone(),
            system: "Compress this conversation into a dense factual summary. Preserve all \
                     names, numbers, decisions, stated preferences, and tool results. Be concise."
                .to_string(),
            messages: vec![Message::User {
                content: formatted_text.to_string(),
            }],
            tools: vec![],
            max_tokens: 2048,
        };

        let response = self
            .llm_client
            .complete(request)
            .await
            .map_err(|e| e.to_string())?;

        // Extract text from response
        let text = response
            .content
            .iter()
            .filter_map(|block| match block {
                ContentBlock::Text { text } => Some(text.clone()),
                _ => None,
            })
            .collect::<Vec<_>>()
            .join("\n");

        if text.is_empty() {
            return Err("summarization LLM returned empty response".to_string());
        }

        Ok(text)
    }
}

